import{_ as t,o,c as a,ag as n}from"./chunks/framework.D4O_uTxf.js";const h=JSON.parse('{"title":"Context Management Strategy","description":"","frontmatter":{},"headers":[],"relativePath":"CLAUDE.md","filePath":"CLAUDE.md","lastUpdated":1771844172000}'),i={name:"CLAUDE.md"};function r(s,e,l,d,c,u){return o(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="context-management-strategy" tabindex="-1">Context Management Strategy <a class="header-anchor" href="#context-management-strategy" aria-label="Permalink to &quot;Context Management Strategy&quot;">​</a></h1><h2 id="the-manager-pattern" tabindex="-1">The Manager Pattern <a class="header-anchor" href="#the-manager-pattern" aria-label="Permalink to &quot;The Manager Pattern&quot;">​</a></h2><p><strong>CRITICAL</strong>: Operate as a strategic manager, not a worker. Delegate to subagents.</p><h3 id="keep-in-main-context" tabindex="-1">Keep in Main Context <a class="header-anchor" href="#keep-in-main-context" aria-label="Permalink to &quot;Keep in Main Context&quot;">​</a></h3><ul><li>User intent and requirements</li><li>Strategic decisions and trade-offs</li><li>Summaries of completed work</li><li>Critical architectural knowledge</li></ul><h3 id="delegate-to-subagents" tabindex="-1">Delegate to Subagents <a class="header-anchor" href="#delegate-to-subagents" aria-label="Permalink to &quot;Delegate to Subagents&quot;">​</a></h3><ul><li>File exploration (&gt;3 files)</li><li>Pattern searches across codebase</li><li>Multi-file implementations</li><li>Long command sequences</li><li>Test execution</li></ul><hr><h2 id="delegation-quick-reference" tabindex="-1">Delegation Quick Reference <a class="header-anchor" href="#delegation-quick-reference" aria-label="Permalink to &quot;Delegation Quick Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Need</th><th>Delegate To</th><th>Example Prompt</th></tr></thead><tbody><tr><td>Find code patterns</td><td><code>Explore</code></td><td>&quot;Find all error handling patterns&quot;</td></tr><tr><td>Design approach</td><td><code>Plan</code></td><td>&quot;Design auth implementation strategy&quot;</td></tr><tr><td>Run commands</td><td><code>Bash</code></td><td>&quot;Run test suite and report failures&quot;</td></tr><tr><td>Multi-step implementation</td><td><code>general-purpose</code></td><td>&quot;Implement and test feature X&quot;</td></tr><tr><td>Agent/droid tasks</td><td><strong>Native CLI</strong> or <strong>thegent</strong></td><td>See Subagent deployment below</td></tr><tr><td>Quick isolated fix</td><td>DO NOT delegate</td><td>Handle directly</td></tr></tbody></table><h3 id="parallel-vs-sequential" tabindex="-1">Parallel vs Sequential <a class="header-anchor" href="#parallel-vs-sequential" aria-label="Permalink to &quot;Parallel vs Sequential&quot;">​</a></h3><p><strong>Parallel</strong> (no dependencies):</p><ul><li>Launch 2-3 explore agents simultaneously for independent searches</li></ul><p><strong>Sequential</strong> (dependent):</p><ol><li>explore -&gt; receive summary</li><li>plan based on findings -&gt; receive plan</li><li>implement approved plan</li></ol><hr><h2 id="subagent-swarm-async-orchestration" tabindex="-1">Subagent swarm (async orchestration) <a class="header-anchor" href="#subagent-swarm-async-orchestration" aria-label="Permalink to &quot;Subagent swarm (async orchestration)&quot;">​</a></h2><p><strong>If you have subagent/swarm capabilities:</strong> Use them as an <strong>async swarm</strong> so you can keep working and reawaken as tasks finish.</p><ul><li><strong>Call task agents async.</strong> Do not block on each one. Fire tasks so that as each completes, you are <strong>reawoken</strong> and can re-evaluate, spawn more agents, or do more work yourself. The system can reawake you on each agent completion.</li><li><strong>Run a swarm.</strong> You can run many task agents in parallel (use best judgment; break down and isolate tasks well). <strong>Max 50 concurrent task agents at a time</strong>—not 5. Scale up when the work is well decomposed and independent.</li><li><strong>Work in between.</strong> While tasks run async, use your own context to do planning, monitoring, or other work. Monitor spawned agents and react when they complete.</li><li><strong>Reawaken on completion.</strong> When you go idle, you will be reawoken as each agent completes. Use that to: spawn more agents for the next batch, do follow-up work, or consolidate results. Effectively: call a swarm → stay available → reawake on each completion → spawn more or continue until done.</li></ul><h3 id="subagent-deployment-native-cli-thegent" tabindex="-1">Subagent deployment: native CLI + thegent <a class="header-anchor" href="#subagent-deployment-native-cli-thegent" aria-label="Permalink to &quot;Subagent deployment: native CLI + thegent&quot;">​</a></h3><p>Use <strong>both</strong> native subagents (when present in CLI tools) and thegent subagents:</p><ul><li><strong>Native subagents:</strong> Cursor Agent, Gemini CLI, Codex subagent, Copilot CLI, Claude Code—invoke these directly when the tool exposes subagent/agent capabilities (e.g. <code>cursor agent</code>, <code>codex-subagent</code>).</li><li><strong>Thegent subagents:</strong> <code>thegent run gemini</code>, <code>thegent run droid</code>, <code>thegent run cursor</code>, <code>thegent run codex</code>, <code>thegent run copilot</code>, <code>thegent run claude</code>—use thegent for unified orchestration, model passthrough, and droid dispatch.</li></ul><p>Prefer native when you need tool-specific behavior; use thegent for cross-provider orchestration, droids, or when model/env control is needed. See <code>docs/reference/THGENT_QUICK_REFERENCE.md</code>.</p><hr><h2 id="anti-patterns" tabindex="-1">Anti-Patterns <a class="header-anchor" href="#anti-patterns" aria-label="Permalink to &quot;Anti-Patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Bad</th><th>Good</th></tr></thead><tbody><tr><td>Reading 10 files to &quot;understand&quot;</td><td>Delegate exploration, get summary</td></tr><tr><td>Editing files for multi-file changes</td><td>Delegate to <code>general-purpose</code></td></tr><tr><td>Sequential explorations one-by-one</td><td>Batch parallel explores</td></tr><tr><td>Asking subagent for &quot;all results&quot;</td><td>Ask for &quot;summary&quot; or &quot;key files&quot;</td></tr></tbody></table><hr><h2 id="context-budget-rule" tabindex="-1">Context Budget Rule <a class="header-anchor" href="#context-budget-rule" aria-label="Permalink to &quot;Context Budget Rule&quot;">​</a></h2><p>If task adds &gt;2000 tokens of file content/output, <strong>delegate it</strong>.</p><hr><h2 id="optionality-and-failure-behavior" tabindex="-1">Optionality and failure behavior <a class="header-anchor" href="#optionality-and-failure-behavior" aria-label="Permalink to &quot;Optionality and failure behavior&quot;">​</a></h2><p><strong>Project stance (required):</strong> <strong>Require</strong> dependencies where they belong; <strong>require</strong> clear, loud failures—no silent or “graceful” degradation.</p><ul><li><strong>Force requirement where it belongs.</strong> Do not make dependencies “optional” just to avoid startup or runtime failure. If a service or config is required for correctness (e.g. go-backend, temporal-host, database), treat it as required and fail when it is missing or down.</li><li><strong>Fail clearly, not silently.</strong> You <strong>must</strong> use explicit failures (preflight failed, runtime error)—not continuing with reduced functionality, logging-only warnings, or hiding errors. Users and operators <strong>must</strong> see <em>what</em> failed (e.g. named items: <code>go-backend; temporal-host</code>) and that the process did not silently degrade.</li><li><strong>Graceful in other ways.</strong> Be “graceful” only via: retries with visible feedback (e.g. “Waiting for X… (2/6)”); error messages that list each failing item (semicolon- or newline-separated); actionable messages and non-obscure stack traces. Do <em>not</em> use optionality or silent fallbacks as a substitute for fixing or starting the real dependency.</li></ul><p>When adding preflight checks, startup logic, or error handling, follow this stance; do not suggest making required dependencies optional to “fix” failures.</p><hr><h2 id="planner-agents-no-code-in-docs-or-plans" tabindex="-1">Planner agents: no code in docs or plans <a class="header-anchor" href="#planner-agents-no-code-in-docs-or-plans" aria-label="Permalink to &quot;Planner agents: no code in docs or plans&quot;">​</a></h2><p><strong>Planner agents</strong> (e.g. PM, Analyst, Architect, SM, TEA, UX Designer, Tech Writer, BMad Master) must <strong>never write code</strong>, especially in documentation and plans. Their job is to <strong>equip others</strong>—engineer agents or humans—to create code or act on docs. Write specs, acceptance criteria, architecture decisions, and clear handoffs; do not write implementation. Avoid stuffing docs or plans with code where it is not directly relevant; prefer references, file paths, or brief pseudocode when necessary.</p><hr><h2 id="phased-wbs-and-plans-with-dags" tabindex="-1">Phased WBS and plans with DAGs <a class="header-anchor" href="#phased-wbs-and-plans-with-dags" aria-label="Permalink to &quot;Phased WBS and plans with DAGs&quot;">​</a></h2><p>When generating <strong>plans</strong>, <strong>roadmaps</strong>, or <strong>implementation breakdowns</strong>, use a <strong>phased Work Breakdown Structure (WBS)</strong> and model <strong>dependencies as a DAG</strong> (directed acyclic graph).</p><ul><li><strong>Phases:</strong> Structure work into ordered phases (e.g. Phase 1: Discovery/Scope, Phase 2: Design, Phase 3: Build, Phase 4: Test/Validate, Phase 5: Deploy/Handoff). Each phase contains deliverable-oriented work packages.</li><li><strong>DAG:</strong> Tasks have explicit <strong>predecessors</strong>; no cycles. List dependencies so execution order is unambiguous (e.g. &quot;Task B depends on A; C depends on B&quot; or a table with <strong>Depends On</strong>).</li><li><strong>Output:</strong> Prefer a phased WBS (hierarchy by phase) plus a dependency list or small DAG (text or diagram). Optionally a table: <strong>Phase | Task ID | Description | Depends On</strong>.</li><li><strong>Planner agents:</strong> When producing plans or PRDs, always use phased WBS and DAG-style dependencies so implementers and PMs can schedule and parallelize correctly.</li></ul><hr><h2 id="timescales-agent-led-aggressive-estimates" tabindex="-1">Timescales: agent-led, aggressive estimates <a class="header-anchor" href="#timescales-agent-led-aggressive-estimates" aria-label="Permalink to &quot;Timescales: agent-led, aggressive estimates&quot;">​</a></h2><p><strong>Assume an agent-driven, agent-led environment.</strong> No user or external human intervention beyond prompts and basic elicitation. Do not emit tasks that require the user or stakeholders to do work.</p><ul><li><strong>Forbidden in plans:</strong> &quot;Schedule external security audit&quot;, &quot;Stakeholder Presentation: Present master plan&quot;, &quot;Team Kickoff: Assign owners for Phase 1&quot;, &quot;Human checkpoint&quot;, &quot;Get approval from X&quot;, or any step that assigns work to a human. Agents own execution and handoffs; if a deliverable is needed (e.g. a presentation or owner manifest), agents produce it.</li><li><strong>Effort in agent terms only:</strong> Reframe all effort as <strong>agent actions</strong> (tool calls, subagent batches). Use <strong>aggressive</strong> wall-clock: err on the side of shorter estimates—if in doubt, use the lower bound.</li><li><strong>Rough mapping (aggressive):</strong><ul><li>1 response / trivial change: 1–2 tool calls, &lt;1 min wall clock</li><li>Small feature (one endpoint, one component): 3–6 tool calls, 1–3 min wall clock</li><li>Cross-stack feature (2–3 areas): 8–15 tool calls or 2–3 parallel subagents, 3–8 min wall clock</li><li>Major refactor or new module: 15–30 tool calls or 3–5 parallel subagents, 8–20 min wall clock</li><li>Multi-phase initiative: decompose into agent batches; each batch 10–20 min wall clock max; no &quot;days&quot; or &quot;weeks&quot; in execution estimates</li></ul></li><li><strong>Forbidden phrasing:</strong> &quot;This will take 2 days&quot;, &quot;Schedule a review&quot;, &quot;Assign owners&quot;, &quot;Present to stakeholders&quot;, &quot;Human validation required&quot;. Use: &quot;N tool calls&quot;, &quot;N parallel subagents&quot;, &quot;~M min wall clock&quot;, &quot;Agent-produced artifact X&quot;.</li></ul><hr><h1 id="project-development-instructions" tabindex="-1">Project Development Instructions <a class="header-anchor" href="#project-development-instructions" aria-label="Permalink to &quot;Project Development Instructions&quot;">​</a></h1><h2 id="dev-environment-and-agents-rtm-dev-make-dev" tabindex="-1">Dev environment and agents (rtm dev / make dev) <a class="header-anchor" href="#dev-environment-and-agents-rtm-dev-make-dev" aria-label="Permalink to &quot;Dev environment and agents (rtm dev / make dev)&quot;">​</a></h2><p><strong>The user runs <code>make dev-tui</code> in their own terminal</strong> as the primary observation dashboard. <strong>Never</strong> run <code>make dev</code>, <code>make dev-tui</code>, or <code>make dev-down</code> — those are user-only commands that would disrupt their session.</p><p><strong>Services use hot reload</strong> (Air for Go, uvicorn --reload for Python, Vite HMR for frontend). Save files and let watchers pick up changes — do not restart services just because you edited code.</p><h3 id="cli-commands-for-introspection-and-manipulation" tabindex="-1">CLI commands for introspection and manipulation <a class="header-anchor" href="#cli-commands-for-introspection-and-manipulation" aria-label="Permalink to &quot;CLI commands for introspection and manipulation&quot;">​</a></h3><p>Use these to operate on the <strong>same running stack</strong> without disrupting the user&#39;s TUI:</p><table tabindex="0"><thead><tr><th>Action</th><th>Command</th></tr></thead><tbody><tr><td>Check all service health</td><td><code>make dev-status</code></td></tr><tr><td>Restart one service</td><td><code>make dev-restart SERVICE=go-backend</code></td></tr><tr><td>Tail logs (all)</td><td><code>make dev-logs</code></td></tr><tr><td>Tail logs (one service)</td><td><code>make dev-logs SERVICE=python-backend</code></td></tr><tr><td>Raw process list</td><td><code>process-compose process list --port 18080</code></td></tr><tr><td>Stop one service</td><td><code>process-compose process stop &lt;name&gt; --port 18080</code></td></tr><tr><td>Start one service</td><td><code>process-compose process start &lt;name&gt; --port 18080</code></td></tr></tbody></table><p>All commands talk to the running process-compose instance via <code>--port 18080</code>. The user sees updates live in their TUI.</p><h3 id="when-to-restart-a-service" tabindex="-1">When to restart a service <a class="header-anchor" href="#when-to-restart-a-service" aria-label="Permalink to &quot;When to restart a service&quot;">​</a></h3><ul><li><strong>Code edits:</strong> Do NOT restart — hot reload handles it.</li><li><strong>Config/env changes:</strong> Restart the affected service only (<code>make dev-restart SERVICE=X</code>).</li><li><strong>Dependency changes</strong> (go.mod, package.json): Restart the affected service.</li><li><strong>Service crash:</strong> Check logs first (<code>make dev-logs SERVICE=X</code>), then restart if needed.</li><li><strong>Never restart the whole stack</strong> unless the user explicitly asks.</li></ul><h3 id="logs" tabindex="-1">Logs <a class="header-anchor" href="#logs" aria-label="Permalink to &quot;Logs&quot;">​</a></h3><ul><li>One log file per service under <strong><code>.process-compose/logs/</code></strong>. Logs are <strong>ephemeral</strong> (truncated on each <code>make dev</code> / <code>make dev-tui</code> start). <ul><li>Examples: <code>.process-compose/logs/go-backend.log</code>, <code>.process-compose/logs/python-backend.log</code>, <code>.process-compose/logs/frontend.log</code>, <code>.process-compose/logs/caddy.log</code></li></ul></li><li><strong>Lifecycle markers:</strong> Each app service log includes injected <code>[LIFECYCLE] START &lt;service&gt; &lt;timestamp&gt;</code> at start and <code>[LIFECYCLE] STOP &lt;service&gt; &lt;timestamp&gt; exit=&lt;code&gt;</code> on exit so restarts are obvious.</li><li>Prefer reading logs via <code>make dev-logs SERVICE=X</code> or the log files directly. Never attach to the user&#39;s TUI terminal.</li></ul><h2 id="package-manager" tabindex="-1">Package Manager <a class="header-anchor" href="#package-manager" aria-label="Permalink to &quot;Package Manager&quot;">​</a></h2><p><strong>Always use <code>bun</code> instead of <code>npm</code> for all package management tasks.</strong></p><ul><li>Install: <code>bun install</code> (not <code>npm install</code>)</li><li>Run scripts: <code>bun run &lt;script&gt;</code> (not <code>npm run &lt;script&gt;</code>)</li><li>Add dependencies: <code>bun add &lt;package&gt;</code> (not <code>npm install &lt;package&gt;</code>)</li><li>Dev dependencies: <code>bun add -d &lt;package&gt;</code> (not <code>npm install --save-dev &lt;package&gt;</code>)</li></ul><h2 id="native-services-over-docker-local-oss-free-only" tabindex="-1">Native services over Docker; local OSS/free only <a class="header-anchor" href="#native-services-over-docker-local-oss-free-only" aria-label="Permalink to &quot;Native services over Docker; local OSS/free only&quot;">​</a></h2><p><strong>Prefer native services over Docker</strong> for development and tooling. Run Postgres, Redis, Caddy, Prometheus, etc. as <strong>native processes</strong> (e.g. via <code>make install-native</code> and process-compose). Use Docker only when native install is not feasible (e.g. CI, production image) or explicitly required. Do not recommend Docker-first for local dev when native orchestration is available.</p><p><strong>Strictly prefer local, OSS, and free.</strong> Do <strong>not</strong> recommend paid online services (SaaS, cloud APIs, paid tiers) when local or free alternatives exist. Prefer: self-hosted, open-source, free-tier, or local tooling. If a feature requires external services, prefer OSS/self-hosted or free options first; document paid options only as fallback and label them clearly. No &quot;use service X (paid)&quot; as the default recommendation.</p><hr><h1 id="bmad-method-claude-code-instructions" tabindex="-1">BMAD Method - Claude Code Instructions <a class="header-anchor" href="#bmad-method-claude-code-instructions" aria-label="Permalink to &quot;BMAD Method - Claude Code Instructions&quot;">​</a></h1><h2 id="activating-agents" tabindex="-1">Activating Agents <a class="header-anchor" href="#activating-agents" aria-label="Permalink to &quot;Activating Agents&quot;">​</a></h2><p>BMAD agents are installed as slash commands in <code>.claude/commands/bmad/</code>.</p><h3 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to Use&quot;">​</a></h3><ol><li><strong>Type Slash Command</strong>: Start with <code>/</code> to see available commands</li><li><strong>Select Agent</strong>: Type <code>/bmad-{agent-name}</code> (e.g., <code>/bmad-dev</code>)</li><li><strong>Execute</strong>: Press Enter to activate that agent persona</li></ol><h3 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/bmad:bmm:agents:dev - Activate development agent</span></span>
<span class="line"><span>/bmad:bmm:agents:architect - Activate architect agent</span></span>
<span class="line"><span>/bmad:bmm:workflows:dev-story - Execute dev-story workflow</span></span></code></pre></div><h3 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><ul><li>Commands are autocompleted when you type <code>/</code></li><li>Agent remains active for the conversation</li><li>Start a new conversation to switch agents</li></ul><hr><h2 id="documentation-organization" tabindex="-1">Documentation Organization <a class="header-anchor" href="#documentation-organization" aria-label="Permalink to &quot;Documentation Organization&quot;">​</a></h2><p><strong>CRITICAL</strong>: All project documentation follows a strict organization structure.</p><h3 id="root-level-files-keep-in-root" tabindex="-1">Root-Level Files (Keep in Root) <a class="header-anchor" href="#root-level-files-keep-in-root" aria-label="Permalink to &quot;Root-Level Files (Keep in Root)&quot;">​</a></h3><p>Only these files should remain in the project root:</p><ul><li><code>README.md</code> - Main project documentation</li><li><code>CHANGELOG.md</code> - Project changelog</li><li><code>AGENTS.md</code> - AI agent instructions</li><li><code>CLAUDE.md</code> / <code>claude.md</code> - Claude-specific instructions</li><li><code>00_START_HERE.md</code> - Getting started guide (if applicable)</li></ul><h3 id="documentation-structure" tabindex="-1">Documentation Structure <a class="header-anchor" href="#documentation-structure" aria-label="Permalink to &quot;Documentation Structure&quot;">​</a></h3><p>All other <code>.md</code> files must be organized in <code>docs/</code> subdirectories:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docs/</span></span>
<span class="line"><span>├── guides/              # Implementation guides and how-tos</span></span>
<span class="line"><span>│   └── quick-start/     # Quick start guides</span></span>
<span class="line"><span>├── reports/             # Completion reports, summaries, status reports</span></span>
<span class="line"><span>├── research/            # Research summaries, indexes, analysis</span></span>
<span class="line"><span>├── reference/           # Quick references, API references</span></span>
<span class="line"><span>└── checklists/          # Implementation checklists, verification lists</span></span></code></pre></div><h3 id="file-organization-rules" tabindex="-1">File Organization Rules <a class="header-anchor" href="#file-organization-rules" aria-label="Permalink to &quot;File Organization Rules&quot;">​</a></h3><p><strong>When creating or moving documentation:</strong></p><ol><li><p><strong>Quick Starts</strong> → <code>docs/guides/quick-start/</code></p><ul><li>Files matching <code>*QUICK_START*.md</code> or <code>*QUICKSTART*.md</code></li></ul></li><li><p><strong>Quick References</strong> → <code>docs/reference/</code></p><ul><li>Files matching <code>*QUICK_REFERENCE*.md</code> or <code>*QUICK_REF*.md</code></li></ul></li><li><p><strong>Implementation Guides</strong> → <code>docs/guides/</code></p><ul><li>Files matching <code>*IMPLEMENTATION_GUIDE*.md</code> or <code>*GUIDE*.md</code></li><li>General implementation documentation</li></ul></li><li><p><strong>Completion Reports</strong> → <code>docs/reports/</code></p><ul><li>Files matching <code>*COMPLETE*.md</code>, <code>*COMPLETION*.md</code>, <code>*SUMMARY*.md</code>, <code>*REPORT*.md</code></li><li>Phase completion files (<code>PHASE_*.md</code>)</li><li>Test-related reports (<code>*TEST*.md</code>)</li></ul></li><li><p><strong>Research Files</strong> → <code>docs/research/</code></p><ul><li>Files matching <code>*RESEARCH*.md</code> or <code>*INDEX*.md</code></li></ul></li><li><p><strong>Checklists</strong> → <code>docs/checklists/</code></p><ul><li>Files matching <code>*CHECKLIST*.md</code></li></ul></li></ol><h3 id="ai-agent-instructions" tabindex="-1">AI Agent Instructions <a class="header-anchor" href="#ai-agent-instructions" aria-label="Permalink to &quot;AI Agent Instructions&quot;">​</a></h3><p><strong>When working as Claude:</strong></p><ul><li><strong>NEVER</strong> create <code>.md</code> files in the project root (except the allowed files above)</li><li><strong>ALWAYS</strong> place new documentation in the appropriate <code>docs/</code> subdirectory</li><li><strong>VERIFY</strong> file location before creating documentation</li><li><strong>MOVE</strong> misplaced files to correct subdirectories if found</li><li><strong>REFERENCE</strong> this structure when users ask about documentation organization</li></ul><h3 id="maintenance" tabindex="-1">Maintenance <a class="header-anchor" href="#maintenance" aria-label="Permalink to &quot;Maintenance&quot;">​</a></h3><ul><li>Use the <code>organize_docs.sh</code> script to reorganize misplaced files</li><li>Keep root directory clean and organized</li><li>Reference this structure in all documentation creation workflows</li></ul><hr><h2 id="documentation-organization-1" tabindex="-1">Documentation Organization <a class="header-anchor" href="#documentation-organization-1" aria-label="Permalink to &quot;Documentation Organization&quot;">​</a></h2><p><strong>CRITICAL</strong>: All project documentation follows a strict organization structure.</p><h3 id="root-level-files-keep-in-root-1" tabindex="-1">Root-Level Files (Keep in Root) <a class="header-anchor" href="#root-level-files-keep-in-root-1" aria-label="Permalink to &quot;Root-Level Files (Keep in Root)&quot;">​</a></h3><p>Only these files should remain in the project root:</p><ul><li><code>README.md</code> - Main project documentation</li><li><code>CHANGELOG.md</code> - Project changelog</li><li><code>AGENTS.md</code> - AI agent instructions</li><li><code>CLAUDE.md</code> - This file (Claude-specific instructions)</li><li><code>00_START_HERE.md</code> - Getting started guide (if applicable)</li></ul><h3 id="documentation-structure-1" tabindex="-1">Documentation Structure <a class="header-anchor" href="#documentation-structure-1" aria-label="Permalink to &quot;Documentation Structure&quot;">​</a></h3><p>All other <code>.md</code> files must be organized in <code>docs/</code> subdirectories:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docs/</span></span>
<span class="line"><span>├── guides/              # Implementation guides and how-tos</span></span>
<span class="line"><span>│   └── quick-start/     # Quick start guides</span></span>
<span class="line"><span>├── reports/             # Completion reports, summaries, status reports</span></span>
<span class="line"><span>├── research/            # Research summaries, indexes, analysis</span></span>
<span class="line"><span>├── reference/           # Quick references, API references</span></span>
<span class="line"><span>└── checklists/          # Implementation checklists, verification lists</span></span></code></pre></div><h3 id="file-organization-rules-1" tabindex="-1">File Organization Rules <a class="header-anchor" href="#file-organization-rules-1" aria-label="Permalink to &quot;File Organization Rules&quot;">​</a></h3><p><strong>When creating or moving documentation:</strong></p><ol><li><p><strong>Quick Starts</strong> → <code>docs/guides/quick-start/</code></p><ul><li>Files matching <code>*QUICK_START*.md</code> or <code>*QUICKSTART*.md</code></li></ul></li><li><p><strong>Quick References</strong> → <code>docs/reference/</code></p><ul><li>Files matching <code>*QUICK_REFERENCE*.md</code> or <code>*QUICK_REF*.md</code></li></ul></li><li><p><strong>Implementation Guides</strong> → <code>docs/guides/</code></p><ul><li>Files matching <code>*IMPLEMENTATION_GUIDE*.md</code> or <code>*GUIDE*.md</code></li><li>General implementation documentation</li></ul></li><li><p><strong>Completion Reports</strong> → <code>docs/reports/</code></p><ul><li>Files matching <code>*COMPLETE*.md</code>, <code>*COMPLETION*.md</code>, <code>*SUMMARY*.md</code>, <code>*REPORT*.md</code></li><li>Phase completion files (<code>PHASE_*.md</code>)</li><li>Test-related reports (<code>*TEST*.md</code>)</li></ul></li><li><p><strong>Research Files</strong> → <code>docs/research/</code></p><ul><li>Files matching <code>*RESEARCH*.md</code> or <code>*INDEX*.md</code></li></ul></li><li><p><strong>Checklists</strong> → <code>docs/checklists/</code></p><ul><li>Files matching <code>*CHECKLIST*.md</code></li></ul></li></ol><h3 id="ai-agent-instructions-1" tabindex="-1">AI Agent Instructions <a class="header-anchor" href="#ai-agent-instructions-1" aria-label="Permalink to &quot;AI Agent Instructions&quot;">​</a></h3><p><strong>When working as Claude:</strong></p><ul><li><strong>NEVER</strong> create <code>.md</code> files in the project root (except the allowed files above)</li><li><strong>ALWAYS</strong> place new documentation in the appropriate <code>docs/</code> subdirectory</li><li><strong>VERIFY</strong> file location before creating documentation</li><li><strong>MOVE</strong> misplaced files to correct subdirectories if found</li><li><strong>REFERENCE</strong> this structure when users ask about documentation organization</li></ul><h3 id="maintenance-1" tabindex="-1">Maintenance <a class="header-anchor" href="#maintenance-1" aria-label="Permalink to &quot;Maintenance&quot;">​</a></h3><ul><li>Use the <code>organize_docs.sh</code> script to reorganize misplaced files</li><li>Keep root directory clean and organized</li><li>Reference this structure in all documentation creation workflows</li></ul><h2 id="development-philosophy" tabindex="-1">Development Philosophy <a class="header-anchor" href="#development-philosophy" aria-label="Permalink to &quot;Development Philosophy&quot;">​</a></h2><h3 id="extend-never-duplicate" tabindex="-1">Extend, Never Duplicate <a class="header-anchor" href="#extend-never-duplicate" aria-label="Permalink to &quot;Extend, Never Duplicate&quot;">​</a></h3><ul><li>NEVER create a v2 file. Refactor the original.</li><li>NEVER create a new class if an existing one can be made generic.</li><li>NEVER create custom implementations when an OSS library exists.</li><li>Before writing ANY new code: search the codebase for existing patterns.</li></ul><h3 id="primitives-first" tabindex="-1">Primitives First <a class="header-anchor" href="#primitives-first" aria-label="Permalink to &quot;Primitives First&quot;">​</a></h3><ul><li>Build generic building blocks before application logic.</li><li>A provider interface + registry is better than N isolated classes.</li><li>Template strings &gt; hardcoded messages. Config-driven &gt; code-driven.</li></ul><h3 id="research-before-implementing" tabindex="-1">Research Before Implementing <a class="header-anchor" href="#research-before-implementing" aria-label="Permalink to &quot;Research Before Implementing&quot;">​</a></h3><ul><li>Check project deps (<code>pyproject.toml</code>) for existing libraries.</li><li>Search PyPI before writing custom code.</li><li>For non-trivial algorithms: check GitHub for 80%+ implementations to fork/adapt.</li></ul><hr><h2 id="library-preferences-do-not-reinvent" tabindex="-1">Library Preferences (DO NOT REINVENT) <a class="header-anchor" href="#library-preferences-do-not-reinvent" aria-label="Permalink to &quot;Library Preferences (DO NOT REINVENT)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Need</th><th>Use</th><th>NOT</th></tr></thead><tbody><tr><td>Retry/resilience</td><td>tenacity</td><td>Custom retry loops</td></tr><tr><td>HTTP client</td><td>httpx</td><td>Custom wrappers</td></tr><tr><td>Logging</td><td>loguru + structlog</td><td>print() or logging.getLogger</td></tr><tr><td>Config</td><td>pydantic-settings</td><td>Manual env parsing</td></tr><tr><td>CLI</td><td>typer</td><td>argparse</td></tr><tr><td>Validation</td><td>pydantic</td><td>Manual if/else</td></tr><tr><td>Rate limiting</td><td>tenacity + asyncio.Semaphore</td><td>Custom rate limiter class</td></tr><tr><td>Serialization</td><td>msgspec / msgpack</td><td>manual json or unsafe alternatives</td></tr><tr><td>Database ORM</td><td>SQLAlchemy (async)</td><td>Raw SQL strings</td></tr><tr><td>API framework</td><td>FastAPI + uvicorn</td><td>Flask / custom ASGI</td></tr><tr><td>MCP tools</td><td>fastmcp</td><td>Custom MCP protocol handling</td></tr><tr><td>Workflow orchestration</td><td>temporalio</td><td>Custom job queues</td></tr></tbody></table><hr><h2 id="code-quality-non-negotiables" tabindex="-1">Code Quality Non-Negotiables <a class="header-anchor" href="#code-quality-non-negotiables" aria-label="Permalink to &quot;Code Quality Non-Negotiables&quot;">​</a></h2><ul><li>Zero new lint suppressions without inline justification</li><li>All new code must pass: <code>ruff check</code>, <code>ty check</code>, tests</li><li>Max function: 40 lines. Max cognitive complexity: 15.</li><li>No placeholder TODOs in committed code</li><li>Hook-backed enforcement: <code>suppression-blocker.sh</code>, <code>post-edit-checker.sh</code>, <code>complexity-ratchet.sh</code></li></ul><hr><h2 id="verifiable-constraints" tabindex="-1">Verifiable Constraints <a class="header-anchor" href="#verifiable-constraints" aria-label="Permalink to &quot;Verifiable Constraints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metric</th><th>Threshold</th><th>Enforcement</th></tr></thead><tbody><tr><td>Test coverage</td><td>&gt;= 90%</td><td><code>pytest --cov-fail-under=90</code></td></tr><tr><td>Cyclomatic complexity</td><td>&lt;= 10 per function</td><td>complexity-ratchet hook</td></tr><tr><td>Cognitive complexity</td><td>&lt;= 15 per function</td><td>complexity-ratchet hook</td></tr><tr><td>Code duplication</td><td>&lt; 5%</td><td>jscpd threshold</td></tr><tr><td>Security findings</td><td>0 high/critical</td><td>bandit + gitleaks + semgrep</td></tr><tr><td>Architecture boundaries</td><td>import-linter enforced</td><td><code>lint-imports</code></td></tr><tr><td>Docstring coverage</td><td>&gt;= 85%</td><td>interrogate</td></tr></tbody></table><hr><h2 id="opinionated-quality-enforcement" tabindex="-1">Opinionated Quality Enforcement <a class="header-anchor" href="#opinionated-quality-enforcement" aria-label="Permalink to &quot;Opinionated Quality Enforcement&quot;">​</a></h2><ul><li>We want opinionated rules that enforce opinionated styling to a strict degree.</li><li>This is an exclusively agent/vibecoded project; programmatic enforcement must guard against bad quality and antipatterns.</li><li>Rather than disables or ignores, fix code properly.</li></ul><h2 id="multi-actor-coordination" tabindex="-1">Multi-Actor Coordination <a class="header-anchor" href="#multi-actor-coordination" aria-label="Permalink to &quot;Multi-Actor Coordination&quot;">​</a></h2><ul><li><strong>Debounce Commands</strong>: Use <code>make lint</code>, <code>make test</code>, <code>make quality</code>, <code>make validate</code>. They are wrapped in <code>smart-command.sh</code> to prevent concurrent execution conflicts between multiple agents.</li><li><strong>Shared Service Management</strong>: <code>process-compose</code> is the source of truth. Use <code>make dev-status</code> to check health and <code>make dev-restart SERVICE=X</code> for graceful restarts.</li><li><strong>Hold-if-Running Logic</strong>: App services and infrastructure use wrappers that allow multiple actors to share processes without force-killing.</li><li><strong>Lock Directory</strong>: Active command locks are stored in <code>.process-compose/locks/</code>.</li><li><strong>Naming Explosion Consolidation</strong>: Prefer consolidated Makefile/Taskfile targets over a multitude of specialized ones.</li></ul>`,129)])])}const p=t(i,[["render",r]]);export{h as __pageData,p as default};
